#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
W-14(이미 다른 커밋 a7ea877에서 처리됨 — 이 스크립트는 건드리지 않음) +
W-16(prompts/manifest.json -> prompts/sp-catalog.json 개명, 남은 부분) +
jeju-router.js 이름충돌 명확화 주석.

★ 안전장치: 전부 "정확한 부분 문자열 치환" 방식이다(파일 전체를 덮어쓰지
않음) — 이 스크립트를 만든 시점 이후 다른 세션이 같은 파일을 더 고쳤어도,
대상 문자열이 그대로 남아있으면 정상 적용되고, 이미 지워졌거나 바뀌었으면
그 파일만 [SKIP]/[FAIL]로 표시하고 나머지는 계속 진행한다 — 절대 파일을
통째로 예전 버전으로 되돌리지 않는다.

이미 적용된 patch는 자동으로 [SKIP]된다(멱등) — 여러 번 실행해도 안전.

포함 내용:
  - prompts/manifest.json -> prompts/sp-catalog.json 개명(파일 자체 rename)
  - 31개 파일의 "manifest.json" 문자열 참조를 "sp-catalog.json"으로 갱신
    (코드 9 + 테스트 2 + 도구스크립트 6 + 워크플로 2 + SP/문서 11 +
    jeju-router.js 명확화 주석 1)
  - 루트 PWA manifest.json / services/*/manifest.json 은 외부 규약(브라우저
    표준·GOPANG_MANUAL.md 문서화된 서비스 등록 규격)에 묶여 있어 그대로 둠
  - prompts/archive/, DEPRECATED, 비-최신 SP-AUTHOR/SP-18 버전 등 과거
    스냅샷은 역사 왜곡을 피하기 위해 의도적으로 건드리지 않음

검증 완료: node --check 전체 통과, node --test로 24개 테스트 전부 통과,
python3 tools/build_manifest.py 실제 실행해 sp-catalog.json 131개 키로
정상 재생성 확인(2026-07-09 origin/main HEAD 346087c 기준).

실행 위치: gopang 저장소 루트
"""
import base64
import json
import os

PAYLOAD_B64 = ""

EDITS = json.loads(base64.b64decode(PAYLOAD_B64))

RENAME_OLD = "prompts/manifest.json"
RENAME_NEW = "prompts/sp-catalog.json"

ok_count = 0
skip_count = 0
fail_count = 0

# 1) 파일명 개명 (이미 개명돼 있으면 건너뜀)
if os.path.exists(RENAME_OLD) and not os.path.exists(RENAME_NEW):
    os.rename(RENAME_OLD, RENAME_NEW)
    print(f"[OK] 개명: {RENAME_OLD} -> {RENAME_NEW}")
    ok_count += 1
elif os.path.exists(RENAME_NEW):
    print(f"[SKIP] 이미 개명됨: {RENAME_NEW}")
    skip_count += 1
else:
    print(f"[FAIL] 개명 대상 없음: {RENAME_OLD} (파일명이 이미 다르게 바뀌었을 수 있음 — 확인 필요)")
    fail_count += 1

# 2) 31개 파일 문자열 패치
for path, subs in EDITS.items():
    if not os.path.exists(path):
        print(f"[FAIL] 파일 없음: {path}")
        fail_count += 1
        continue
    with open(path, encoding="utf-8") as f:
        content = f.read()
    changed = False
    for old, new in subs:
        if new in content:
            continue  # 이미 적용됨
        if old not in content:
            print(f"[FAIL] {path}: 패치 대상을 못 찾음(다른 세션이 이 부분을 이미 바꿨을 수 있음) -> {old[:60]!r}")
            fail_count += 1
            continue
        content = content.replace(old, new, 1)
        changed = True
        ok_count += 1
    if changed:
        with open(path, "w", encoding="utf-8") as f:
            f.write(content)
        print(f"[OK] 패치 적용: {path}")
    else:
        print(f"[SKIP] 이미 전부 적용됨: {path}")
        skip_count += 1

print()
print(f"완료 — 적용 {ok_count} / 건너뜀 {skip_count} / 실패 {fail_count}")
if fail_count:
    print("★ 실패 항목이 있으면 해당 파일은 수동 확인 필요 — 다른 파일은 정상 적용됐습니다.")
